/**
 * CreateGraphRequest
 *
 * Request model for creating a new graph.
 *
 * Use this to create either:
 * - **Entity graphs**: Standard graphs with entity schema. Requires `initial_entity`.
 * - **Custom graphs**: Generic graphs with a fully custom schema. Requires `custom_schema`; `initial_entity` is not used.
 */
export type CreateGraphRequest = {
    /**
     * Graph metadata including name, description, and schema extensions
     */
    metadata: GraphMetadata;
    /**
     * Instance Tier
     *
     * Instance tier: ladybug-standard, ladybug-large, ladybug-xlarge
     */
    instance_tier?: string;
    /**
     * Custom schema definition to apply. If provided, creates a generic custom graph. If omitted, creates an entity graph using schema_extensions.
     */
    custom_schema?: CustomSchemaDefinition | null;
    /**
     * Initial entity for the graph. Required for entity graphs (when custom_schema is omitted). Omit only when providing custom_schema for a generic graph.
     */
    initial_entity?: InitialEntityData | null;
    /**
     * Create Entity
     *
     * Whether to create the entity node and upload initial data. Only applies when initial_entity is provided. Set to False to create graph without populating entity data (useful for file-based ingestion workflows).
     */
    create_entity?: boolean;
    /**
     * Tags
     *
     * Optional tags for organization
     */
    tags?: Array<string>;
};

/**
 * CreateInformationBlockRequest
 *
 * Generic create request — discriminator + typed-at-dispatch payload.
 *
 * ``block_type`` selects the registry entry. ``payload`` is validated
 * against ``BlockTypeRegistryEntry.create_request_model`` (e.g.
 * :class:`CreateScheduleRequest` for ``block_type='schedule'``) by the
 * command dispatcher. Chosen over a Pydantic discriminated union on the
 * top-level request so adding a block type is one registry line, not a
 * union-arm edit at the request-model layer.
 */
export type CreateInformationBlockRequest = {
    /**
     * Block Type
     *
     * Block type discriminator. Must match a registered entry in robosystems.operations.information_block.registry.REGISTRY.
     */
    block_type: string;
    /**
     * Payload
     *
     * Block-type-specific creation payload. Shape-validated against the registry entry's `create_request_model` at dispatch time; the validation error surfaces as a 422 at the API boundary.
     */
    payload?: {
        [key: string]: unknown;
    };
};

